def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity == 0:
            continue
        ratio = item / capacity
        if ratio > 1.2:
            priorities[i] = np.inf
            continue
        if ratio == 1:
            priorities[i] = 0
            continue
        gap = capacity - item
        base_score = 0
        for p in range(1, 21):
            sign = 1 if p % 3 == 0 else (-1) ** p
            base_score += sign * (ratio ** p) / (p + gap if gap != 0 else p + 1)
        penalty = 0
        consecutive_zeros = 0
        for k in range(i, min(n, i + 5)):
            if bins[k] == 0:
                consecutive_zeros += 1
            else:
                overlap = item / bins[k]
                if 0 < overlap < 1:
                    penalty += (1 - overlap) ** 3
        penalty /= (consecutive_zeros + 1)
        adjustment = 1.0
        if gap < item * 0.5:
            adjustment *= 2.5
        elif gap < item:
            adjustment *= 1.8
        elif gap < item * 1.5:
            adjustment *= 1.3
        for _ in range(consecutive_zeros):
            adjustment *= 0.9
        final_score = -base_score * adjustment + penalty
        if final_score < 0:
            final_score = 0
        if i % 2 == 0 and capacity > item * 2:
            final_score *= 0.8
        priorities[i] = final_score
    return priorities
